<span class="line"><span style="color:#E1E4E8;">    </span><span style="color:#B392F0;">@wraps</span><span style="color:#E1E4E8;">(</span><span style="color:#79B8FF;">cls</span><span style="color:#E1E4E8;">)</span></span>
